import React, { useState, useEffect } from 'react';

const clientId = 'YOUR_CLIENT_ID';
const clientSecret = 'YOUR_CLIENT_SECRET';
const redirectUri = 'http://localhost:3000/callback';
const authorizationEndpoint = 'https://your-auth-server.com/oauth/authorize';
const tokenEndpoint = 'https://your-auth-server.com/oauth/token';
const scope = 'read write';

function App() {
  const [accessToken, setAccessToken] = useState(localStorage.getItem('accessToken'));
  const [authCode, setAuthCode] = useState(null);

  useEffect(() => {
    if (authCode) {
      fetchAccessToken(authCode);
    }
  }, [authCode]);

  const handleLogin = () => {
    window.location.href = `${authorizationEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}&scope=${scope}`;
  };

  const fetchAccessToken = async (code) => {
    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: redirectUri,
          client_id: clientId,
          client_secret: clientSecret,
        }),
      });

      const data = await response.json();
      setAccessToken(data.access_token);
      localStorage.setItem('accessToken', data.access_token);
    } catch (error) {
      console.error('Error fetching access token:', error);
    }
  };

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    if (code) {
      setAuthCode(code);
      window.history.replaceState({}, '', redirectUri); // Remove the code from the URL
    }
  }, []);

  return (
    <div>
      {accessToken ? (
        <h1>Logged In</h1>
      ) : (
        <button onClick={handleLogin}>Login with OAuth</button>
      )}
    </div>
  );
}

export default App;